import { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface CurrentWeather {
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  icon?: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'stormy';
}

interface ForecastDay {
  day: string;
  high: number;
  low: number;
  condition: string;
  icon?: 'sunny' | 'cloudy' | 'rainy' | 'snowy' | 'stormy';
}

interface Props {
  city?: string;
  current?: CurrentWeather;
  forecast?: ForecastDay[];
  onSubmit?: (data: unknown) => void;
}

const weatherEmojis: Record<string, string> = {
  sunny: '☀️',
  cloudy: '☁️',
  rainy: '🌧️',
  snowy: '❄️',
  stormy: '⛈️',
};

export default function GeneratedComponent({
  city = 'San Francisco',
  current = {
    temperature: 72,
    condition: 'Partly Cloudy',
    humidity: 65,
    windSpeed: 12,
    icon: 'cloudy',
  },
  forecast = [
    { day: 'Tomorrow', high: 75, low: 62, condition: 'Sunny', icon: 'sunny' },
    { day: 'Wednesday', high: 73, low: 61, condition: 'Cloudy', icon: 'cloudy' },
    { day: 'Thursday', high: 68, low: 58, condition: 'Rainy', icon: 'rainy' },
    { day: 'Friday', high: 70, low: 60, condition: 'Partly Cloudy', icon: 'cloudy' },
    { day: 'Saturday', high: 76, low: 63, condition: 'Sunny', icon: 'sunny' },
  ],
  onSubmit,
}: Props) {
  const { motionEnabled } = useMotion();

  const getAnimationDelay = (index: number): string => {
    const delayMs = index * 50;
    return delayMs + 'ms';
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md">
        <Card
          padding="var(--ggui-spacing-lg, 24px)"
          shadow="md"
          style={{
            background: `linear-gradient(135deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-700, #0369a1))`,
            animation: motionEnabled ? 'ggui-slideInUp 200ms ease-out both' : 'none',
          }}
        >
          {/* Header - City and Basic Info */}
          <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-lg, 24px)')}>
            <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-sm, 8px)')}>
              <Text
                variant="h2"
                color="var(--ggui-color-primary-50, #f0f9ff)"
                weight="bold"
              >
                {city}
              </Text>
              <Text
                variant="body"
                color="var(--ggui-color-primary-100, #e0f2fe)"
              >
                {new Date().toLocaleDateString('en-US', {
                  weekday: 'long',
                  month: 'long',
                  day: 'numeric',
                })}
              </Text>
            </Stack>

            {/* Current Weather */}
            <Stack
              direction="vertical"
              gap={parseInt('var(--ggui-spacing-md, 16px)')}
              style={{
                backgroundColor: 'rgba(255, 255, 255, 0.1)',
                padding: 'var(--ggui-spacing-lg, 24px)',
                borderRadius: 'var(--ggui-radius-lg, 12px)',
                backdropFilter: 'blur(10px)',
              }}
            >
              {/* Temperature and Condition */}
              <Row align="center" gap={parseInt('var(--ggui-spacing-md, 16px)')}>
                <div
                  style={{
                    fontSize: '4rem',
                    lineHeight: '1',
                  }}
                >
                  {weatherEmojis[current.icon || 'sunny']}
                </div>
                <Stack direction="vertical" gap={0}>
                  <Text
                    variant="h1"
                    color="var(--ggui-color-primary-50, #f0f9ff)"
                    weight="bold"
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                      lineHeight: '1.2',
                    }}
                  >
                    {current.temperature}°F
                  </Text>
                  <Text
                    color="var(--ggui-color-primary-100, #e0f2fe)"
                    weight="medium"
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-lg, 18px)',
                    }}
                  >
                    {current.condition}
                  </Text>
                </Stack>
              </Row>

              {/* Humidity and Wind Speed */}
              <Row
                gap={parseInt('var(--ggui-spacing-lg, 24px)')}
                justify="around"
                style={{
                  marginTop: 'var(--ggui-spacing-md, 16px)',
                  paddingTop: 'var(--ggui-spacing-md, 16px)',
                  borderTop: '1px solid rgba(255, 255, 255, 0.2)',
                }}
              >
                <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-xs, 4px)')} align="center">
                  <Text
                    color="var(--ggui-color-primary-100, #e0f2fe)"
                    style={{ fontSize: 'var(--ggui-typography-fontSize-sm, 14px)' }}
                  >
                    Humidity
                  </Text>
                  <Text
                    color="var(--ggui-color-primary-50, #f0f9ff)"
                    weight="semibold"
                    style={{ fontSize: 'var(--ggui-typography-fontSize-lg, 18px)' }}
                  >
                    {current.humidity}%
                  </Text>
                </Stack>

                <div
                  style={{
                    width: '1px',
                    backgroundColor: 'rgba(255, 255, 255, 0.2)',
                  }}
                />

                <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-xs, 4px)')} align="center">
                  <Text
                    color="var(--ggui-color-primary-100, #e0f2fe)"
                    style={{ fontSize: 'var(--ggui-typography-fontSize-sm, 14px)' }}
                  >
                    Wind Speed
                  </Text>
                  <Text
                    color="var(--ggui-color-primary-50, #f0f9ff)"
                    weight="semibold"
                    style={{ fontSize: 'var(--ggui-typography-fontSize-lg, 18px)' }}
                  >
                    {current.windSpeed} mph
                  </Text>
                </Stack>
              </Row>
            </Stack>

            {/* 5-Day Forecast */}
            <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-md, 16px)')}>
              <Text
                color="var(--ggui-color-primary-50, #f0f9ff)"
                weight="semibold"
                style={{ fontSize: 'var(--ggui-typography-fontSize-base, 16px)' }}
              >
                5-Day Forecast
              </Text>

              <Row
                gap={parseInt('var(--ggui-spacing-sm, 8px)')}
                wrap={true}
                justify="between"
              >
                {forecast.map((day, index) => (
                  <Card
                    key={day.day}
                    padding="var(--ggui-spacing-md, 16px)"
                    shadow="none"
                    border={false}
                    style={{
                      backgroundColor: 'rgba(255, 255, 255, 0.15)',
                      backdropFilter: 'blur(10px)',
                      flex: '1 1 calc(20% - 8px)',
                      minWidth: '80px',
                      animation: motionEnabled
                        ? 'ggui-slideInUp 200ms ease-out ' + getAnimationDelay(index) + ' both'
                        : 'none',
                    }}
                  >
                    <Stack direction="vertical" gap={parseInt('var(--ggui-spacing-sm, 8px)')} align="center">
                      <Text
                        color="var(--ggui-color-primary-100, #e0f2fe)"
                        weight="medium"
                        align="center"
                        style={{ fontSize: 'var(--ggui-typography-fontSize-sm, 14px)' }}
                      >
                        {day.day}
                      </Text>

                      <div
                        style={{
                          fontSize: '2rem',
                          lineHeight: '1',
                        }}
                      >
                        {weatherEmojis[day.icon || 'sunny']}
                      </div>

                      <Text
                        color="var(--ggui-color-primary-50, #f0f9ff)"
                        weight="semibold"
                        align="center"
                        style={{ fontSize: 'var(--ggui-typography-fontSize-base, 16px)' }}
                      >
                        {day.high}°
                      </Text>

                      <Text
                        color="var(--ggui-color-primary-200, #bae6fd)"
                        align="center"
                        style={{ fontSize: 'var(--ggui-typography-fontSize-sm, 14px)' }}
                      >
                        {day.low}°
                      </Text>
                    </Stack>
                  </Card>
                ))}
              </Row>
            </Stack>
          </Stack>
        </Card>
      </Container>
    </>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string; // e.g., "Mon", "Tue"
  icon: string; // e.g., "☀️", "☁️"
  high: number;
  low: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  humidity?: number; // percentage
  windSpeed?: number; // km/h or mph
  forecast?: ForecastDay[];
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  city = "Unknown",
  temperature = 0,
  condition = "Clear",
  humidity = 0,
  windSpeed = 0,
  forecast = [],
  onSubmit
}: Props) {

  // Function to get appropriate emoji based on condition string
  const getWeatherEmoji = (cond: string) => {
    switch (cond.toLowerCase()) {
      case "clear":
      case "sunny":
        return "☀️";
      case "cloudy":
      case "partly cloudy":
        return "☁️";
      case "rainy":
      case "light rain":
      case "heavy rain":
        return "🌧️";
      case "snowy":
        return "🌨️";
      case "stormy":
      case "thunderstorm":
        return "⛈️";
      default:
        return "❓";
    }
  };

  return (
    <Container maxWidth="sm" center={true}>
      <Card
        padding="var(--ggui-spacing-xl, 32px)"
        shadow="md"
        border={false}
        aria-label="Weather information card"
        style={{
          borderRadius: 'var(--ggui-radius-lg, 12px)',
          backgroundColor: 'var(--ggui-color-surface, #ffffff)',
          overflow: 'hidden', // Ensures inner elements respect border radius
          boxShadow: 'var(--ggui-shadow-lg, 0 10px 15px -3px rgba(0,0,0,0.1))',
        }}
      >
        <Stack direction="vertical" gap="var(--ggui-spacing-lg, 24px)" align="center">
          {/* City Name */}
          <Text
            variant="h2"
            color="var(--ggui-color-text-primary, #111827)"
            style={{
              fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
              fontSize: 'var(--ggui-typography-fontSize-3xl, 30px)',
            }}
          >
            {city}
          </Text>

          {/* Current Temperature and Condition */}
          <Stack direction="vertical" align="center" gap="var(--ggui-spacing-sm, 8px)">
            <Text
              color="var(--ggui-color-primary-600, #0284c7)"
              style={{
                fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                lineHeight: 1, // Reduce line height for large text
              }}
            >
              {temperature}°C
            </Text>
            <Row align="center" gap="var(--ggui-spacing-xs, 4px)">
              <Text style={{ fontSize: 'var(--ggui-typography-fontSize-xl, 20px)' }}>
                {getWeatherEmoji(condition)}
              </Text>
              <Text
                variant="h3"
                color="var(--ggui-color-text-secondary, #6b7280)"
                style={{
                  fontWeight: 'var(--ggui-typography-fontWeight-medium, 500)',
                  fontSize: 'var(--ggui-typography-fontSize-lg, 18px)',
                }}
              >
                {condition}
              </Text>
            </Row>
          </Stack>

          {/* Humidity and Wind Speed */}
          <Row justify="center" gap="var(--ggui-spacing-lg, 24px)">
            <Stack direction="vertical" align="center" gap="var(--ggui-spacing-xs, 4px)">
              <Text
                color="var(--ggui-color-text-secondary, #6b7280)"
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                  fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                }}
              >
                Humidity
              </Text>
              <Text
                color="var(--ggui-color-text-primary, #111827)"
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-base, 16px)',
                }}
              >
                {humidity}%
              </Text>
            </Stack>
            <Stack direction="vertical" align="center" gap="var(--ggui-spacing-xs, 4px)">
              <Text
                color="var(--ggui-color-text-secondary, #6b7280)"
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                  fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                }}
              >
                Wind
              </Text>
              <Text
                color="var(--ggui-color-text-primary, #111827)"
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-base, 16px)',
                }}
              >
                {windSpeed} km/h
              </Text>
            </Stack>
          </Row>

          <Divider
            orientation="horizontal"
            margin="var(--ggui-spacing-sm, 8px)"
            style={{
              backgroundColor: 'var(--ggui-color-gray-200, #e5e7eb)',
              width: '100%', // Ensure it spans full width
            }}
          />

          {/* 5-day Forecast */}
          <Stack
            direction="horizontal"
            justify="between"
            wrap={true}
            gap="var(--ggui-spacing-md, 16px)"
            style={{ width: '100%' }}
          >
            {forecast.map((dayForecast, index) => (
              <Stack
                key={index}
                direction="vertical"
                align="center"
                gap="var(--ggui-spacing-xs, 4px)"
                style={{ flex: 1, minWidth: '60px' }} // Allow items to grow/shrink but have a min width
              >
                <Text
                  variant="caption"
                  color="var(--ggui-color-text-secondary, #6b7280)"
                  style={{
                    fontWeight: 'var(--ggui-typography-fontWeight-medium, 500)',
                    fontSize: 'var(--ggui-typography-fontSize-xs, 12px)',
                  }}
                >
                  {dayForecast.day}
                </Text>
                <Text style={{ fontSize: 'var(--ggui-typography-fontSize-lg, 18px)' }}>
                  {getWeatherEmoji(dayForecast.icon)}
                </Text>
                <Row gap="var(--ggui-spacing-xs, 4px)">
                  <Text
                    color="var(--ggui-color-text-primary, #111827)"
                    style={{
                      fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                      fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                    }}
                  >
                    {dayForecast.high}°
                  </Text>
                  <Text
                    color="var(--ggui-color-text-secondary, #6b7280)"
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                    }}
                  >
                    {dayForecast.low}°
                  </Text>
                </Row>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
